class Solution(object):
    def minDifference(self, n, k):
        divs = [f for f in range(1, int(n**0.5) + 1) if n % f == 0]
        full_divs = []
        for f in divs:
            full_divs.append(f)
            if f != n // f:
                full_divs.append(n // f)
        full_divs.sort()
        best_diff = [float('inf')]
        best_parts = [None]
        def dfs(rem_n, rem_k, parts, lo_idx):
            if rem_k == 1:
                parts.append(rem_n)
                d = max(parts) - min(parts)
                if d < best_diff[0]:
                    best_diff[0] = d
                    best_parts[0] = sorted(parts[:])
                parts.pop()
                return
            for i in range(lo_idx, len(full_divs)):
                f = full_divs[i]
                if f > rem_n:
                    break
                if rem_n % f == 0:
                    parts.append(f)
                    dfs(rem_n // f, rem_k - 1, parts, i)
                    parts.pop()
        dfs(n, k, [], 0)
        return best_parts[0]
